     1→"use client";
     2→
     3→import { useState, Suspense } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import useSWR from "swr";
     6→import Link from "next/link";
     7→import {
     8→  semanticReleases as srApi,
     9→  projects as projectsApi,
    10→} from "@/lib/api/client";
    11→import { VersionChip } from "@/components/ui/version-chip";
    12→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    13→import { Trash2 } from "lucide-react";
    14→import { timeAgo } from "@/lib/format";
    15→import type { Project, SemanticRelease } from "@/lib/api/types";
    16→
    17→/* ---------- Urgency chip ---------- */
    18→
    19→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    20→  critical: { bg: "#dc2626", text: "#ffffff" },
    21→  high: { bg: "#f97316", text: "#ffffff" },
    22→  medium: { bg: "#f59e0b", text: "#ffffff" },
    23→  low: { bg: "#6b7280", text: "#ffffff" },
    24→};
    25→
    26→function UrgencyChip({ urgency }: { urgency: string }) {
    27→  const u = urgency.toLowerCase();
    28→  const style = URGENCY_COLORS[u];
    29→  if (!style) return null;
    30→  return (
    31→    <span
    32→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    33→      style={{ backgroundColor: style.bg, color: style.text }}
    34→    >
    35→      {urgency}
    36→    </span>
    37→  );
    38→}
    39→
    40→/* ---------- Helpers ---------- */
    41→
    42→const PER_PAGE = 15;
    43→
    44→/* ---------- Main component ---------- */
    45→
    46→export function SemanticReleasesList() {
    47→  return (
    48→    <Suspense>
    49→      <SemanticReleasesListInner />
    50→    </Suspense>
    51→  );
    52→}
    53→
    54→function SemanticReleasesListInner() {
    55→  const searchParams = useSearchParams();
    56→  const initialProject = searchParams.get("project") ?? "all";
    57→  const [page, setPage] = useState(1);
    58→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    59→  const [deletingId, setDeletingId] = useState<string | null>(null);
    60→
    61→  /* Fetch projects for the filter dropdown */
    62→  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    63→    projectsApi.list()
    64→  );
    65→  const projectsById = new Map<string, Project>();
    66→  for (const p of projectsData?.data ?? []) projectsById.set(p.id, p);
    67→
    68→  /* Fetch semantic releases — scoped by project or all */
    69→  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    70→    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    71→    () => srApi.list(projectFilter, page, PER_PAGE)
    72→  );
    73→
    74→  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    75→    projectFilter === "all" ? ["sr-all", page] : null,
    76→    () => srApi.listAll(page, PER_PAGE)
    77→  );
    78→
    79→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    80→  const releases: SemanticRelease[] =
    81→    projectFilter !== "all"
    82→      ? scopedData?.data ?? []
    83→      : allData?.data ?? [];
    84→
    85→  const mutateData = projectFilter !== "all" ? mutateScopedData : mutateAllData;
    86→
    87→  /* Pagination math */
    88→  const activeData = projectFilter !== "all" ? scopedData : allData;
    89→  const total = activeData?.meta?.total ?? 0;
    90→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    91→  const startRow = (page - 1) * PER_PAGE + 1;
    92→  const endRow = Math.min(page * PER_PAGE, total);
    93→
    94→  return (
    95→    <div className="space-y-6 fade-in">
    96→      {/* Page title */}
    97→      <h1
    98→        style={{
    99→          fontFamily: "var(--font-fraunces)",
   100→          fontSize: "24px",
   101→          fontWeight: 700,
   102→          color: "#111113",
   103→        }}
   104→      >
   105→        Semantic Releases
   106→      </h1>
   107→
   108→      {/* Project filter */}
   109→      <div>
   110→        <select
   111→          value={projectFilter}
   112→          onChange={(e) => {
   113→            setProjectFilter(e.target.value);
   114→            setPage(1);
   115→          }}
   116→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   117→          style={{
   118→            fontFamily: "var(--font-dm-sans)",
   119→            fontSize: "13px",
   120→            color: "#111113",
   121→            border: "1px solid #e8e8e5",
   122→          }}
   123→          onFocus={(e) =>
   124→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   125→          }
   126→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   127→        >
   128→          <option value="all">All Projects</option>
   129→          {projectsData?.data.map((p: Project) => (
   130→            <option key={p.id} value={p.id}>
   131→              {p.name}
   132→            </option>
   133→          ))}
   134→        </select>
   135→      </div>
   136→
   137→      {/* Table card */}
   138→      <div
   139→        className="overflow-hidden rounded-lg bg-white"
   140→        style={{ border: "1px solid #e8e8e5" }}
   141→      >
   142→        {isLoading ? (
   143→          <div
   144→            className="py-16 text-center"
   145→            style={{
   146→              fontFamily: "var(--font-dm-sans)",
   147→              fontSize: "13px",
   148→              color: "#6b7280",
   149→            }}
   150→          >
   151→            Loading...
   152→          </div>
   153→        ) : releases.length === 0 ? (
   154→          <div className="py-16 text-center">
   155→            <p
   156→              style={{
   157→                fontFamily: "var(--font-fraunces)",
   158→                fontStyle: "italic",
   159→                fontSize: "15px",
   160→                color: "#9ca3af",
   161→              }}
   162→            >
   163→              No semantic releases yet
   164→            </p>
   165→          </div>
   166→        ) : (
   167→          <table className="w-full">
   168→            <thead>
   169→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   170→                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   171→                  (col) => (
   172→                    <th
   173→                      key={col}
   174→                      className="px-4 py-3 text-left"
   175→                      style={{
   176→                        fontFamily: "var(--font-dm-sans)",
   177→                        fontSize: "11px",
   178→                        fontWeight: 600,
   179→                        textTransform: "uppercase" as const,
   180→                        letterSpacing: "0.08em",
   181→                        color: "#9ca3af",
   182→                      }}
   183→                    >
   184→                      {col}
   185→                    </th>
   186→                  )
   187→                )}
   188→              </tr>
   189→            </thead>
   190→            <tbody>
   191→              {releases.map((sr) => {
   192→                const project = projectsById.get(sr.project_id);
   193→                return (
   194→                  <tr
   195→                    key={sr.id}
   196→                    className="transition-colors hover:bg-[#fafaf9]"
   197→                    style={{ borderBottom: "1px solid #e8e8e5" }}
   198→                  >
   199→                    {/* Project */}
   200→                    <td className="px-4 py-3">
   201→                      {project ? (
   202→                        <Link
   203→                          href={`/projects/${project.id}`}
   204→                          className="hover:underline"
   205→                          style={{
   206→                            fontFamily: "var(--font-dm-sans)",
   207→                            fontSize: "13px",
   208→                            color: "#111113",
   209→                            fontWeight: 500,
   210→                          }}
   211→                        >
   212→                          {project.name}
   213→                        </Link>
   214→                      ) : (
   215→                        <span
   216→                          style={{
   217→                            fontFamily: "var(--font-dm-sans)",
   218→                            fontSize: "13px",
   219→                            color: "#9ca3af",
   220→                          }}
   221→                        >
   222→                          {"\u2014"}
   223→                        </span>
   224→                      )}
   225→                    </td>
   226→
   227→                    {/* Version */}
   228→                    <td className="px-4 py-3">
   229→                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
   230→                        <VersionChip version={sr.version} />
   231→                      </Link>
   232→                    </td>
   233→
   234→                    {/* Status */}
   235→                    <td className="px-4 py-3">
   236→                      <span
   237→                        className="text-[13px] font-medium"
   238→                        style={{
   239→                          fontFamily: "var(--font-dm-sans)",
   240→                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
   241→                        }}
   242→                      >
   243→                        {sr.status}
   244→                      </span>
   245→                    </td>
   246→
   247→                    {/* Urgency */}
   248→                    <td className="px-4 py-3">
   249→                      {sr.report?.urgency ? (
   250→                        <UrgencyChip urgency={sr.report.urgency} />
   251→                      ) : (
   252→                        <span
   253→                          style={{
   254→                            fontFamily: "var(--font-dm-sans)",
   255→                            fontSize: "13px",
   256→                            color: "#9ca3af",
   257→                          }}
   258→                        >
   259→                          {"\u2014"}
   260→                        </span>
   261→                      )}
   262→                    </td>
   263→
   264→                    {/* Age */}
   265→                    <td className="px-4 py-3">
   266→                      <span
   267→                        style={{
   268→                          fontFamily: "var(--font-dm-sans)",
   269→                          fontSize: "13px",
   270→                          color: "#9ca3af",
   271→                        }}
   272→                      >
   273→                        {timeAgo(sr.completed_at ?? sr.created_at)}
   274→                      </span>
   275→                    </td>
   276→
   277→                    {/* Delete */}
   278→                    <td className="px-4 py-3">
   279→                      <button
   280→                        onClick={() => setDeletingId(sr.id)}
   281→                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
   282→                        style={{ color: "#9ca3af" }}
   283→                        title="Delete semantic release"
   284→                      >
   285→                        <Trash2 className="h-4 w-4" />
   286→                      </button>
   287→                    </td>
   288→                  </tr>
   289→                );
   290→              })}
   291→            </tbody>
   292→          </table>
   293→        )}
   294→      </div>
   295→
   296→      {/* Pagination */}
   297→      {total > 0 && (
   298→        <div className="flex items-center justify-between">
   299→          <span
   300→            style={{
   301→              fontFamily: "var(--font-dm-sans)",
   302→              fontSize: "13px",
   303→              color: "#9ca3af",
   304→            }}
   305→          >
